mapper.sql:
select a.id, a.title, a.start_time, a.end_time, a.reason, a.type_id, a.create_time, a.update_time, a.create_user, a.update_user, a.status, b.name as create_user_name, c.name as update_user_name, d.name as type_name from tb_leave_approval as a left join tb_user as b on a.create_user = b.id left join tb_user as c on a.update_user = c.id left join tb_approval_type as d on a.type_id = d.id where 1 = 1
and #{param.createTimeMax} >= a.create_time
and a.create_time >= #{param.createTimeMin}
and #{param.updateTimeMax} >= a.update_time
and a.update_time >= #{param.updateTimeMin}
and a.create_user = #{param.createUser}
and a.update_user = #{param.updateUser}
and a.status = #{param.status}
and a.type_id = #{param.typeId}
and a.title like concat('%', #{param.title}, '%')
order by a.create_time desc

mapper.select:
select a.id, a.title, a.start_time, a.end_time, a.reason, a.type_id, a.create_time, a.update_time, a.create_user, a.update_user, a.status, b.name as create_user_name, c.name as update_user_name, d.name as type_name, f.ID_ as task_id from tb_leave_approval as a left join tb_user as b on a.create_user = b.id left join tb_user as c on a.update_user = c.id left join tb_approval_type as d on a.type_id = d.id inner join act_ru_variable as e on a.id = cast(e.LONG_ as unsigned) inner join act_ru_task as f on f.PROC_INST_ID_ = e.PROC_INST_ID_ where 1 = 1 and e.NAME_ = 'businessId' and f.ASSIGNEE_ = #{param.approvalUser}
and #{param.createTimeMax} >= a.create_time
and a.create_time >= #{param.createTimeMin}
and #{param.updateTimeMax} >= a.update_time
and a.update_time >= #{param.updateTimeMin}
and a.create_user = #{param.createUser}
and a.update_user = #{param.updateUser}
and a.status = #{param.status}
and a.type_id = #{param.typeId}
order by a.create_time desc

select count(*) as totalCount, sum(case when status = 'pending' then 1 else 0 end) as pendingCount, sum(case when status = 'approved' then 1 else 0 end) as approvedCount, sum(case when status = 'rejected' then 1 else 0 end) as rejectedCount from tb_leave_approval where 1=1 and create_user = #{userId}
and create_time >= #{startTime}
and #{endTime} >= create_time

select count(distinct cast(a.LONG_ as unsigned)) from act_hi_varinst as a inner join act_hi_taskinst as b on a.PROC_INST_ID_ = b.PROC_INST_ID_ where 1 = 1 and a.NAME_ = 'businessId' and b.ASSIGNEE_ = #{userId}
and b.END_TIME_ >= #{startTime}
and #{endTime} >= b.END_TIME_
